import { IWavesCrypto, TBinaryOut, TSeed, ISeedRelated, ISeedEmbeded } from './interface';
type TOutputTypesMap = {
    Bytes: Uint8Array;
    Base58: string;
};
type TDefaultOut = 'Base58';
type TOutput = keyof TOutputTypesMap;
